//go:build amd64

package matchlen

import "golang.org/x/sys/cpu"

// bulkMatchSSE (16-byte SSE2) and bulkMatchAVX2 (32-byte AVX2) compare a and b up
// to limit, returning the match length. Generated by go-asmgen (bulkmatch_gen.go),
// in bulkmatch_amd64.s.
func bulkMatchSSE(a, b []byte, limit int) int
func bulkMatchAVX2(a, b []byte, limit int) int

var hasAVX2 = cpu.X86.HasAVX2

func bulkMatch(a, b []byte, limit int) int {
	if hasAVX2 {
		return bulkMatchAVX2(a, b, limit)
	}
	return bulkMatchSSE(a, b, limit)
}
